        content = file.read()
    if any(k in content.lower() for k in ['fault', 'defect', 'quality', 'natural', 'variation', 'unrelated', 'rejection']):
        print(f)
        # print some surrounding text
        lines = content.split('\n')
        for i, l in enumerate(lines):
            if any(k in l.lower() for k in ['fault', 'defect', 'quality', 'natural', 'variation', 'unrelated', 'rejection']):
                print(f'  Line {i}: {l}')
